// Java 25 - Flexible constructor bodies (JEP 513, final)
// Learn: validate arguments before calling super().
class Shape {
    Shape(double area) {
    }
}

class Square extends Shape {
    final double side;

    Square(double side) {
        if (side <= 0) {
            throw new IllegalArgumentException("side must be positive");
        }
        super(side * side); // runs after the validation above
        this.side = side;
    }
}
